<template><div class="panel-section"><h2 class="section-heading">編碼取回與矩陣</h2><p class="section-sub">頻次只供研究探索，不代表主題重要性或研究結論。</p>
<div class="card filter-row"><select class="form-select" v-model="filters.code_id"><option value="">所有 Codes</option><option v-for="c in store.codes" :key="c.id" :value="c.id">{{c.name}}</option></select><select class="form-select" v-model="filters.interview_id"><option value="">所有訪談</option><option v-for="i in store.interviews" :key="i.id" :value="i.id">{{i.title}}</option></select><select class="form-select" v-model="filters.case_id"><option value="">所有 Cases</option><option v-for="c in store.cases" :key="c.id" :value="c.id">{{c.name}}</option></select><select class="form-select" v-model="filters.speaker_id"><option value="">所有 Speakers</option><option v-for="s in speakers" :key="s.speaker_id" :value="s.speaker_id">{{s.speaker_name}}</option></select><select class="form-select" v-model="filters.attribute_definition_id"><option value="">所有 Case attributes</option><option v-for="d in store.attributeDefinitions" :key="d.id" :value="d.id">{{d.name}}</option></select><input v-if="filters.attribute_definition_id" class="form-input" v-model="filters.attribute_value" placeholder="屬性值"><select class="form-select" v-model="dimension"><option value="interview">Code × Interview</option><option value="case">Code × Case</option></select><button class="btn btn-primary" @click="load">查詢</button></div>
<div class="analysis-grid"><div class="card"><h3>Coded excerpts</h3><div v-for="e in excerpts" :key="e.id" class="excerpt"><strong>{{e.code_name}}</strong> · {{e.interview_title}} · {{e.speaker_name}}<blockquote>{{context(e)}}</blockquote><small>{{e.case_name||'未連結 Case'}}</small></div></div><div class="card matrix-wrap"><h3>{{dimension==='case'?'Code × Case':'Code × Interview'}}</h3><table><thead><tr><th>Code</th><th>對象</th><th>次數</th></tr></thead><tbody><tr v-for="(r,n) in matrix" :key="n"><td>{{r.code_name}}</td><td>{{r.dimension_label||'未關聯'}}</td><td>{{r.count}}</td></tr></tbody></table></div></div></div></template>
<script setup>import{ref,reactive,computed}from'vue';import{api}from'../api/client.js';import{useAppStore}from'../stores/appStore.js';const store=useAppStore(),filters=reactive({code_id:'',interview_id:'',case_id:'',speaker_id:'',attribute_definition_id:'',attribute_value:''}),dimension=ref('interview'),excerpts=ref([]),matrix=ref([]),speakers=computed(()=>[...new Map(store.segments.map(s=>[s.speaker_id,s])).values()].filter(s=>s.speaker_id));async function load(){const p=new URLSearchParams(Object.entries(filters).filter(([,v])=>v));[excerpts.value,matrix.value]=await Promise.all([api(`/v1/projects/${store.currentProjectId}/excerpts?${p}`),api(`/v1/projects/${store.currentProjectId}/matrix?dimension=${dimension.value}`)])}function context(e){return e.segment_text.slice(Math.max(0,e.start_offset-35),e.end_offset+35)}</script>
